    "component_interactions": [
      { "from": "Email Service", "to": "SendGrid API", "status": "risk", "issue": "No circuit breaker. If SendGrid degrades (slow 503s), retries with backoff will pile up, exhaust connection pools and thread/goroutine budget, and cascade failure back into the service. 3 retries × 10s timeout = up to 30s per request under degradation." },
      { "from": "Email Service", "to": "Database", "status": "risk", "issue": "Database is used to store delivery records but health check does not verify connectivity. Silent DB failures would mean emails send but delivery records are lost — creating reconciliation nightmares and invisible data loss." },
      { "from": "Email Service", "to": "Internal Job Queue", "status": "risk", "issue": "Queue depth is not monitored by the health endpoint. A growing queue with no visibility means backpressure goes undetected until emails are severely delayed or the queue OOMs." }
    ],
    "contract_compliance": "SendGrid API integration appears functional with retries and timeouts. However, no mention of idempotency keys on SendGrid calls — retried requests risk duplicate email delivery to end users.",
    "data_flow_integrity": "Risk of silent data loss: if DB write fails after a successful SendGrid send, the email is delivered but unrecorded. No mention of transactional guarantees or compensating actions for this split-brain scenario."
  },

  "observability_review": {
    "logging": {
      "coverage": "adequate",
      "gaps": [
        "No mention of logging queue depth or queue processing latency",
        "No mention of logging DB write failures separately from SendGrid failures",
        "Unclear if retry attempts are logged individually (needed to distinguish transient blips from sustained degradation)"
      ]
    },
    "metrics": {
      "coverage": "Partial — send/fail counters and SendGrid latency are good fundamentals, but critical gaps remain",
      "gaps": [
        "No queue depth metric — cannot detect backpressure or growing lag",
        "No queue processing latency metric (time from enqueue to send)",
        "No DB operation latency or error rate metric",
        "No retry count metric (emails_retried_total) — cannot distinguish clean failures from retry storms",
        "No in-flight request gauge — cannot detect connection pool exhaustion",
        "No metric for duplicate sends (idempotency failures)"
      ]
    },
    "tracing": {
      "coverage": "Not mentioned",
      "gaps": [
        "No distributed tracing mentioned — cannot trace a request from ingestion through queue to SendGrid delivery and DB write",
        "Request ID in logs is a start but insufficient for cross-service correlation"
      ]
    },
    "debugging_capability": "Moderate. Structured JSON logging with request ID, duration, and status code is a solid foundation. However, an on-call engineer at 3am cannot currently answer: 'Why are emails delayed?' (no queue metrics), 'Is the DB healthy?' (no DB health signal), or 'Are we in a retry storm?' (no retry metrics). They would be flying blind on 2 of 3 downstream dependencies."
  },

  "resilience_assessment": {
    "failure_modes": [
      {
        "scenario": "SendGrid sustained outage (returns 503 for minutes)",
        "handling": "partial",
        "recommendation": "Add a circuit breaker. Without one, every inbound request spawns 3 retries × 10s = 30s of held connections. At even modest throughput (100 req/s), this exhausts resources in seconds and cascades into full service failure. Circuit breaker should open after N consecutive failures, return fast-fail, and half-open to probe recovery."
      },
      {
        "scenario": "SendGrid slow degradation (responds in 8-9s instead of <1s)",
        "handling": "unhandled",
        "recommendation": "The 10s timeout is too generous for a service that normally responds in <1s. Add an aggressive timeout (e.g., 3s) for the fast path with the 10s as an absolute ceiling. Track p99 latency and alert when it breaches normal bounds. Without this, slow SendGrid silently degrades the entire service."
      },
      {
        "scenario": "Database connection failure",
        "handling": "unhandled",
        "recommendation": "No health check coverage, no dedicated metrics. If the DB goes down, emails may still send but delivery records are lost silently. Add DB connectivity to health check, add DB error rate metrics, and decide on a policy: fail the request (consistent but emails don't send) or send anyway and log for reconciliation (available but inconsistent)."
      },
      {
        "scenario": "Job queue backpressure / saturation",
        "handling": "unhandled",
        "recommendation": "No queue depth monitoring or backpressure mechanism. Add queue depth metric, alert on depth threshold, and implement backpressure (reject new requests with 429 when queue exceeds safe depth)."
      },
      {
        "scenario": "Duplicate email delivery from retried SendGrid calls",
        "handling": "unhandled",
        "recommendation": "If a SendGrid call succeeds but the response is lost (network blip), the retry sends the same email again. Use SendGrid idempotency keys to make retries safe. Without this, users receive duplicate emails during any transient network issue."
      },
      {
        "scenario": "Poison message in queue (malformed email that always fails)",
        "handling": "unhandled",
        "recommendation": "No dead-letter queue or max-retry-per-message policy mentioned. A poison message will be retried forever, consuming capacity. Add a dead-letter queue and max retry count per message."
      }
    ],
    "retry_config": "3 retries with exponential backoff — reasonable for transient failures. Missing: jitter (to avoid thundering herd on recovery), per-message retry cap for queued items, and idempotency keys to make retries safe.",
    "timeout_config": "10s on SendGrid API calls. Too generous given typical SendGrid response times (<1s). A slow response that takes 9s is effectively a failure for the user but won't be caught. Consider a tiered approach: 3s soft timeout (log warning, count as slow), 10s hard timeout (kill and retry).",
    "circuit_breakers": "MISSING — This is the single highest-priority gap. Without a circuit breaker, a SendGrid outage cascades into total service failure through resource exhaustion.",
    "graceful_degradation": "No degradation strategy defined. The service should have a clear policy for: SendGrid down (queue and retry later vs. reject), DB down (send anyway vs. fail), queue full (reject with 429 vs. drop oldest)."
  },

  "operational_readiness": {
    "deployment_ready": false,
    "rollback_capable": true,
    "rollback_plan": "Redeploy previous container image. Adequate for stateless service logic. However, if a bad deploy corrupts delivery records in the DB, image rollback alone does not fix the data. Confirm DB schema is unchanged between versions.",
    "monitoring_coverage": "Insufficient. Core send/fail metrics exist but 2 of 3 downstream dependencies (DB and queue) have zero monitoring. On-call cannot detect or diagnose DB failures or queue saturation without manual investigation.",
    "on_call_documentation": "Not mentioned. At minimum, need a runbook covering: how to check SendGrid status, how to drain/inspect the queue, how to verify DB health, how to manually retry failed deliveries, and escalation contacts.",
    "new_infrastructure_required": {
      "new_env_vars": [],
      "new_services": [],
      "new_queues_topics": ["Dead-letter queue for poison messages"],
      "config_changes": ["Circuit breaker configuration (failure threshold, open duration, half-open probe count)", "Tiered timeout configuration"],
      "infra_provisioning": []
    },
    "database_safety": {
      "has_migrations": false,
      "reversible": false,
      "data_preserving": true,
      "large_table_impact": false,
      "details": "No migrations mentioned. Delivery records table will grow continuously — ensure retention policy and archival strategy exist to prevent unbounded table growth."
    },
    "verdict": "NOT READY"
  },

  "escalations": [
    {
      "type": "missing_observability",
      "issue": "Database and job queue have zero monitoring coverage",
      "reason": "2 of 3 downstream dependencies (database, job queue) are completely invisible to the health check, metrics, and alerting. An on-call engineer cannot detect DB connection failures or queue saturation. Cannot assess operational readiness for components we cannot observe.",
      "routed_to": "Coach K"
    },
    {
      "type": "missing_observability",
      "issue": "Health endpoint is a lie — reports healthy when critical dependencies are down",
      "reason": "The /health endpoint unconditionally returns 200. Load balancers and orchestrators (k8s liveness/readiness probes) will route traffic to instances with dead DB connections or saturated queues. This actively masks failures. Must add dependency checks: split into /health/live (process is up) and /health/ready (dependencies are reachable, queue depth is acceptable).",
      "routed_to": "Coach K"
    },
    {
      "type": "missing_observability",
      "issue": "No circuit breaker and no retry storm visibility",
      "reason": "Without a circuit breaker on SendGrid and without retry count metrics, the service will silently enter a retry storm during any SendGrid degradation. There is no metric to detect this state and no mechanism to stop the cascade. The combination of missing circuit breaker + missing retry metrics makes this a blind spot that will cause a full outage.",
      "routed_to": "Coach K"
    }
  ],

  "confidence": {
    "level": 55,
    "high_confidence_areas": [
      "SendGrid retry and timeout configuration assessment",
      "Health endpoint inadequacy",
      "Circuit breaker gap identification",
      "Logging foundation is solid"
    ],
    "low_confidence_areas": [
      "Database interaction patterns — no code reviewed, assessing from description only",
